(window.webpackJsonp=window.webpackJsonp||[]).push([[678],{678:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[][]}</span> <span class=\\"hljs-variable\\">points</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> minTimeToVisitAllPoints = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">points</span>) </span>{\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">getSec</span>(<span class=\\"hljs-params\\">a,b</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> xGap=<span class=\\"hljs-built_in\\">Math</span>.abs(b[<span class=\\"hljs-number\\">0</span>]-a[<span class=\\"hljs-number\\">0</span>])\\n    <span class=\\"hljs-keyword\\">let</span> yGap=<span class=\\"hljs-built_in\\">Math</span>.abs(b[<span class=\\"hljs-number\\">1</span>]-a[<span class=\\"hljs-number\\">1</span>])\\n    <span class=\\"hljs-keyword\\">let</span> max=<span class=\\"hljs-built_in\\">Math</span>.max(xGap,yGap)\\n    <span class=\\"hljs-keyword\\">return</span> max\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> init=points[<span class=\\"hljs-number\\">0</span>]\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;points.length;i++){\\n    res+=getSec(init,points[i])\\n    init=points[i]\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"minimum-time-visiting-all-points","hasThinking":false,"content":"<p>\u5e73\u9762\u4e0a\u6709\xa0<code>n</code>\xa0\u4e2a\u70b9\uff0c\u70b9\u7684\u4f4d\u7f6e\u7528\u6574\u6570\u5750\u6807\u8868\u793a <code>points[i] = [x<sub>i</sub>, y<sub>i</sub>]</code> \u3002\u8bf7\u4f60\u8ba1\u7b97\u8bbf\u95ee\u6240\u6709\u8fd9\u4e9b\u70b9\u9700\u8981\u7684 <strong>\u6700\u5c0f\u65f6\u95f4</strong>\uff08\u4ee5\u79d2\u4e3a\u5355\u4f4d\uff09\u3002</p>\\n\\n<p>\u4f60\u9700\u8981\u6309\u7167\u4e0b\u9762\u7684\u89c4\u5219\u5728\u5e73\u9762\u4e0a\u79fb\u52a8\uff1a</p>\\n\\n<ul>\\n\\t<li>\u6bcf\u4e00\u79d2\u5185\uff0c\u4f60\u53ef\u4ee5\uff1a\\n\\t<ul>\\n\\t\\t<li>\u6cbf\u6c34\u5e73\u65b9\u5411\u79fb\u52a8\u4e00\u4e2a\u5355\u4f4d\u957f\u5ea6\uff0c\u6216\u8005</li>\\n\\t\\t<li>\u6cbf\u7ad6\u76f4\u65b9\u5411\u79fb\u52a8\u4e00\u4e2a\u5355\u4f4d\u957f\u5ea6\uff0c\u6216\u8005</li>\\n\\t\\t<li>\u8de8\u8fc7\u5bf9\u89d2\u7ebf\u79fb\u52a8 <code>sqrt(2)</code> \u4e2a\u5355\u4f4d\u957f\u5ea6\uff08\u53ef\u4ee5\u770b\u4f5c\u5728\u4e00\u79d2\u5185\u5411\u6c34\u5e73\u548c\u7ad6\u76f4\u65b9\u5411\u5404\u79fb\u52a8\u4e00\u4e2a\u5355\u4f4d\u957f\u5ea6\uff09\u3002</li>\\n\\t</ul>\\n\\t</li>\\n\\t<li>\u5fc5\u987b\u6309\u7167\u6570\u7ec4\u4e2d\u51fa\u73b0\u7684\u987a\u5e8f\u6765\u8bbf\u95ee\u8fd9\u4e9b\u70b9\u3002</li>\\n\\t<li>\u5728\u8bbf\u95ee\u67d0\u4e2a\u70b9\u65f6\uff0c\u53ef\u4ee5\u7ecf\u8fc7\u8be5\u70b9\u540e\u9762\u51fa\u73b0\u7684\u70b9\uff0c\u4f46\u7ecf\u8fc7\u7684\u90a3\u4e9b\u70b9\u4e0d\u7b97\u4f5c\u6709\u6548\u8bbf\u95ee\u3002</li>\\n</ul>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2019/11/24/1626_example_1.png\\" style=\\"height: 428px; width: 500px;\\" /></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>points = [[1,1],[3,4],[-1,0]]\\n<strong>\u8f93\u51fa\uff1a</strong>7\\n<strong>\u89e3\u91ca\uff1a</strong>\u4e00\u6761\u6700\u4f73\u7684\u8bbf\u95ee\u8def\u5f84\u662f\uff1a <strong>[1,1]</strong> -> [2,2] -> [3,3] -> <strong>[3,4] </strong>-> [2,3] -> [1,2] -> [0,1] -> <strong>[-1,0]</strong>   \\n\u4ece [1,1] \u5230 [3,4] \u9700\u8981 3 \u79d2 \\n\u4ece [3,4] \u5230 [-1,0] \u9700\u8981 4 \u79d2\\n\u4e00\u5171\u9700\u8981 7 \u79d2</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>points = [[3,2],[-2,2]]\\n<strong>\u8f93\u51fa\uff1a</strong>5\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>points.length == n</code></li>\\n\\t<li><code>1 <= n\xa0<= 100</code></li>\\n\\t<li><code>points[i].length == 2</code></li>\\n\\t<li><code>-1000\xa0<= points[i][0], points[i][1]\xa0<= 1000</code></li>\\n</ul>\\n","title":"1266. \u8bbf\u95ee\u6240\u6709\u70b9\u7684\u6700\u5c0f\u65f6\u95f4","relatedTags":["\u51e0\u4f55","\u6570\u7ec4"],"difficult":"Easy","lang":["javascript"],"uniqueID":"1266"}')}}]);